#!/usr/bin/env python3
"""
Adaptive Strategy

Adaptive market strategy.

Features:
- Market regime detection
- Trend-adaptive signals

Migrated from echo-auto-trading project.
"""

from typing import Dict, List, Optional
from dataclasses import dataclass

from core.strategy import Strategy, Signal, TradingSignal
from core.indicator_cache import get_indicator


@dataclass
class AdaptiveConfig:
    """Adaptive configuration"""
    short_period: int = 7
    long_period: int = 25
    rsi_period: int = 14


class Adaptive(Strategy):
    """Adaptive trading strategy"""

    REQUIRES = ['sma', 'rsi']

    def __init__(self, exchange=None, config: Optional[AdaptiveConfig] = None):
        """Initialize Adaptive strategy"""
        self.exchange = exchange
        self.config = config or AdaptiveConfig()

    @property
    def name(self) -> str:
        return "adaptive"

    def detect_regime(self, klines: List[Dict]) -> Dict:
        """Detect market regime"""
        closes = [c["close"] for c in klines]
        if len(closes) < 30:
            return {"regime": "unknown", "ma_short": 0, "ma_long": 0, "rsi": 50}

        sma_short_series = get_indicator('sma', period=self.config.short_period)
        sma_long_series = get_indicator('sma', period=self.config.long_period)
        rsi_series = get_indicator('rsi', period=self.config.rsi_period)

        ma_short = sma_short_series[self.current_idx]
        ma_long = sma_long_series[self.current_idx]
        rsi = rsi_series[self.current_idx]

        recent = closes[self.current_idx - 9:self.current_idx + 1]
        trend = (sum(recent[-5:]) / 5) - (sum(recent[:5]) / 5)
        if trend > 0 and ma_short > ma_long and rsi > 55:
            regime = "strong_trend"
        elif trend < 0 and ma_short < ma_long and rsi < 45:
            regime = "strong_trend"
        else:
            regime = "moderate_trend"
        return {"regime": regime, "ma_short": ma_short, "ma_long": ma_long, "rsi": rsi}

    def generate_signal(
        self, coin: str, klines: List[Dict] = None
    ) -> TradingSignal:
        """Generate Adaptive signal"""
        min_required = 30
        if not klines or len(klines) < min_required:
            return TradingSignal(signal=Signal.HOLD, confidence=0.0, coin=coin,
                timestamp=klines[-1]["time"] if klines else 0,
                metadata={"reason": "Insufficient klines"})
        regime = self.detect_regime(klines)
        rsi = regime["rsi"]
        ma_short = regime["ma_short"]
        ma_long = regime["ma_long"]
        if regime["regime"] == "strong_trend":
            signal = Signal.BUY if ma_short > ma_long else Signal.SELL
        elif regime["regime"] == "moderate_trend":
            if rsi < 35:
                signal = Signal.BUY
            elif rsi > 65:
                signal = Signal.SELL
            else:
                signal = Signal.HOLD
        else:
            signal = Signal.HOLD
        return TradingSignal(signal=signal, confidence=0.6, coin=coin,
            timestamp=klines[-1]["time"], metadata={"regime": regime["regime"], "rsi": rsi})

